import { siteConfig } from "@/lib/site-config";

type Props = {
  className?: string;
  label?: string;
  /** Appended to default WhatsApp open URL */
  message?: string;
};

export function WhatsAppButton({
  className = "",
  label = "WhatsApp",
  message,
}: Props) {
  const href =
    message && message.length > 0
      ? `${siteConfig.whatsappUrl}?text=${encodeURIComponent(message)}`
      : siteConfig.whatsappUrl;

  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className={`btn-press inline-flex items-center justify-center rounded-full border border-brand-accent/30 bg-white px-5 py-2.5 text-sm font-semibold text-brand-accent shadow-sm transition hover:bg-brand-surface ${className}`}
    >
      {label}
    </a>
  );
}
