import Link from "next/link";

type Props = {
  title: string;
  summary: string;
  priceFrom: number;
  currency: string;
  priceNote?: string;
  bullets?: string[];
  href?: string;
  ctaLabel?: string;
};

export function ServiceCard({
  title,
  summary,
  priceFrom,
  currency,
  priceNote,
  bullets,
  href = "/contact",
  ctaLabel = "Enquire",
}: Props) {
  return (
    <article className="card-hover flex h-full flex-col rounded-2xl border border-brand-border bg-white p-6 shadow-sm">
      <div className="flex items-baseline justify-between gap-2">
        <h3 className="font-serif text-xl font-semibold text-brand-ink">{title}</h3>
        <p className="shrink-0 text-sm font-semibold text-brand-accent">
          from {currency}
          {priceFrom.toLocaleString("en-BD")}
        </p>
      </div>
      <p className="mt-2 text-sm text-brand-muted">{summary}</p>
      {priceNote ? (
        <p className="mt-1 text-xs text-brand-muted/90">{priceNote}</p>
      ) : null}
      {bullets && bullets.length > 0 ? (
        <ul className="mt-4 list-inside list-disc space-y-1 text-sm text-brand-muted">
          {bullets.map((b) => (
            <li key={b}>{b}</li>
          ))}
        </ul>
      ) : null}
      <div className="mt-6">
        <Link
          href={href}
          className="inline-flex rounded-full bg-brand-surface px-4 py-2 text-sm font-semibold text-brand-ink ring-1 ring-brand-border transition hover:bg-brand-accent hover:text-white hover:ring-brand-accent"
        >
          {ctaLabel}
        </Link>
      </div>
    </article>
  );
}
